141	export interface Damage {
142	  itemType: string;
143	  amount: number;
144	}
145	
146	export interface Incident {
147	  cause: string;
148	  damages: Damage[];
149	}
150	
151	export interface Policy {
152	  items: Item[];
153	}
154	
155	export interface ClaimResult {
156	  payout: number;
157	  remainingCap: number;
158	}
159	
160	// Unmodified insurance value per item; the policy's insurance sum (and hence
161	// its payout cap) is derived from these, never from premium modifiers.
162	const INSURANCE_VALUES: Record<string, number> = {
163	  sword: 1000,
164	  amulet: 600,
165	  staff: 800,
166	  potion: 400,
167	  rune: 250,
168	  moonstone: 250,
169	};
170	
171	export const insuranceSum = (items: Item[]): number =>
172	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
173	
174	const DEDUCTIBLE_PER_EVENT = 100;
175	const ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
176	const ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
177	const FULL_REIMBURSEMENT_RATE = 1;
178	
179	// Highly enchanted items (enchantment >= 8) are reimbursed at a reduced rate,
180	// reflecting their volatility under repair.
181	const isHighlyEnchanted = (item: Item): boolean =>
182	  (item.enchantment ?? 0) >= ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
183	
184	// The insured item a damage refers to, looked up by type from the policy, or a
185	// thrown error if the policy does not cover that item type. Damage to an
186	// uninsured item is never reimbursable, and the returned (non-undefined) item
187	// supplies the attributes the reimbursement rate depends on.
188	const requireInsuredItem = (damage: Damage, policy: Policy): Item => {
189	  const item = policy.items.find((item) => item.type === damage.itemType);
190	  if (!item) {
191	    throw new Error(`Damaged item not covered by policy: ${damage.itemType}`);
192	  }
193	  return item;
194	};
195	
196	// A single damage's reimbursement: the covered amount net of the per-event
197	// deductible. The covered amount is the full damage, except for highly
198	// enchanted items, which are covered at ENCHANTMENT_REIMBURSEMENT_RATE.
199	const damageReimbursement = (damage: Damage, policy: Policy): number => {
200	  if (damage.amount < 0) {
201	    throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
202	  }
203	  const item = requireInsuredItem(damage, policy);
204	  const rate = isHighlyEnchanted(item)
205	    ? ENCHANTMENT_REIMBURSEMENT_RATE
206	    : FULL_REIMBURSEMENT_RATE;
207	  const coveredAmount = rate * damage.amount;
208	  return coveredAmount - DEDUCTIBLE_PER_EVENT;
209	};
210	
211	// A policy cannot be claimed for more damages of a type than it insures items
212	// of that type (e.g. two sword damages against a single insured sword).
213	const requireDamagesWithinCover = (incident: Incident, policy: Policy): void => {
214	  const insuredCounts = countByType(policy.items);
215	  const damageCounts = countByType(
216	    incident.damages.map((damage) => ({ type: damage.itemType })),
217	  );
218	  for (const [type, damaged] of damageCounts) {
219	    if (damaged > (insuredCounts.get(type) ?? 0)) {
220	      throw new Error(`More damages than insured items for type: ${type}`);
221	    }
222	  }
223	};
224	
225	export const claim = (
226	  policy: Policy,
227	  incident: Incident,
228	  remainingCap: number,
229	): ClaimResult => {
230	  requireDamagesWithinCover(incident, policy);
231	  const grossPayout = roundDownInMHPCOFavor(
232	    sum(incident.damages.map((damage) => damageReimbursement(damage, policy))),
233	  );
234	  // The policy's remaining cap limits the payout; the desired amount is reduced
235	  // to whatever cap is left.
236	  const payout = Math.min(grossPayout, remainingCap);
237	  return { payout, remainingCap: remainingCap - payout };
238	};
